// Get the Pexels response
const pexelsData = $input.first().json;
const photos = pexelsData.photos || [];

if (!photos || photos.length === 0) {
  return [{
    json: {
      article_with_images: $('write the article').first().json.text,
      image_urls: [],
      featured_image_url: null
    }
  }];
}

// Get the original article
const article = $('write the article').first().json.text;

// Extract keywords from the article for relevance check
// Simple approach: take first 5 words (can improve with NLP)
const keywords = article
  .toLowerCase()
  .match(/\b\w+\b/g)
  ?.slice(0, 5) || [];

// Filter relevant images
const relevantPhotos = photos.filter(photo => {
  const altText = (photo.alt || '').toLowerCase();
  return keywords.some(keyword => altText.includes(keyword));
});

// If no relevant images found, fallback to all
const finalPhotos = relevantPhotos.length > 0 ? relevantPhotos : photos;

// Build image HTML and arrays
let imageHtml = '';
const imageUrls = [];

finalPhotos.forEach((photo, index) => {
  const imgUrl = photo.src.large;
  imageUrls.push(imgUrl);
  imageHtml += `<img src="${imgUrl}" alt="${photo.alt || `Article image ${index+1}`}" />\n`;
});

// Insert images into article
let enhancedArticle = article;
if (article.includes('[IMAGES]')) {
  enhancedArticle = article.replace('[IMAGES]', imageHtml);
} else {
  enhancedArticle = imageHtml + '\n\n' + article;
}

// Return filtered images
return [{
  json: {
    article_with_images: enhancedArticle,
    image_urls: imageUrls,  // Array of filtered URLs
    image_count: finalPhotos.length,
    featured_image_url: imageUrls[0] || null,
    first_image_url: imageUrls[0] || null,
    second_image_url: imageUrls[1] || null,
    third_image_url: imageUrls[2] || null
  }
}];

// ================================================
// COLLECT UPLOADED IMAGE DATA (from media upload node)
// ================================================
const mediaItems = $input.all();  // all uploaded media items
const mediaIds = mediaItems.map(item => item.json.id);
const mediaUrls = mediaItems.map(item => item.json.source_url);

// ================================================
// RETRIEVE ARTICLE AND SEO DATA (using your node names)
// ================================================
const articleNodeName = 'write the article';
const seoNodeName    = 'generate SEO meta data';

// Get article content – using .first().json.text as you specified
const articleText = $('write the article').first().json.text;
// Get SEO metadata – also .first().json.text (likely a JSON string)
const seoText =  $('generate seo meta data').first().json.text;


let seoMeta;
try {
  seoMeta = JSON.parse(seoText);
} catch (e) {
  // If parsing fails, assume it's already an object or fallback
  seoMeta = seoText;
}

// ================================================
// REPLACE IMAGE PLACEHOLDERS WITH WORDPRESS IMAGES
// ================================================
let finalArticle = articleText;

mediaUrls.forEach((url, index) => {
  const placeholder = `[IMAGE:${index + 1}]`; // e.g., [IMAGE:1], [IMAGE:2], ...
  const imgTag = `<img src="${url}" class="wp-image-${mediaIds[index]}" alt="Article image ${index + 1}" />`;

  if (finalArticle.includes(placeholder)) {
    finalArticle = finalArticle.replace(placeholder, imgTag);
  } else {
    // Optional fallback: append at the end if placeholder missing
    finalArticle += `\n\n${imgTag}`;
  }
});

// ================================================
// RETURN SINGLE ITEM FOR WORDPRESS POST NODE
// ================================================
return [{
  json: {
    final_article: finalArticle,
    featured_image_id: mediaIds[0] || null,
    title: seoMeta.seo_title || seoMeta.title || 'Article',
    meta: seoMeta,
    media_ids: mediaIds,
    media_urls: mediaUrls
  }
}];
